    fn cached_binary_reports_miss_then_hit() {
        let cc_available = Command::new("sh")
            .args(["-lc", "command -v cc >/dev/null 2>&1"])
            .status()
            .expect("failed to probe cc")
            .success();
        if !cc_available {
            eprintln!("skipping AOT C cache test because cc is not available");
            return;
        }

        let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
        let fixture_path = manifest_dir.join("../gnode/benchmarks/fib.ts");
        let source = fs::read_to_string(&fixture_path).expect("fixture source should be readable");
        let scan = crate::parse_and_extract_orchestration(&source, &fixture_path.to_string_lossy())
            .expect("fixture should extract");
        let temp_dir = tempfile::tempdir().expect("tempdir should be created");

        let first = prepare_cached_binary(&scan, &source, "app", temp_dir.path())
            .expect("first prepare should compile");
        let second = prepare_cached_binary(&scan, &source, "app", temp_dir.path())
            .expect("second prepare should hit cache");

        assert!(!first.cache_hit);
        assert!(second.cache_hit);
        assert_eq!(first.fingerprint, second.fingerprint);
        assert_eq!(first.binary_path, second.binary_path);
        assert!(second.binary_path.exists());

        let hit = lookup_cached_binary(
            &fixture_path.to_string_lossy(),
            &source,
            "app",
            temp_dir.path(),
        )
        .expect("source-key lookup should hit after prepare");
        assert_eq!(hit.fingerprint, second.fingerprint);
        assert_eq!(hit.binary_path, second.binary_path);
    }

