    fn node(id: &str, labels: &[&str], properties: &[(&str, &str)]) -> GgNode {
        GgNode {
            id: id.to_string(),
            labels: labels.iter().map(|label| (*label).to_string()).collect(),
            properties: properties
                .iter()
                .map(|(key, value)| ((*key).to_string(), (*value).to_string()))
                .collect::<BTreeMap<_, _>>(),
            source_span: None,
        }
    }

