    // ── Numeric-loop emitter: the certified-class parity harness ──
    //
    // These tests are the checked-in form of the walker/AOT differential
    // discipline: for programs inside the certified numeric-loop class,
    // the compiled binary must print EXACTLY the walker's output, and
    // outside-class or divergence-risk cases must decline (exit 3) or
    // refuse to compile (None). The pinned values mirror the Lean
    // oracle pentad in Gnosis/AotParityOracle.lean (gnosis-math).

    const SUM_LOOP_TS: &str =
        "export function main(n) {\n  let s = 0;\n  for (let i = 0; i < n; i++) { s = s + i; }\n  return s;\n}\n";
    const SEQ_LOOPS_TS: &str = "export function main(n) {\n  let s = 0;\n  for (let i = 0; i < n; i++) { s += 1; }\n  for (let j = 0; j < n; j++) { s += 2; }\n  for (let k = 0; k < n; k++) { s += 3; }\n  for (let m = 0; m < n; m++) { s += 4; }\n  return s;\n}\n";
    const BOUNDED_TS: &str =
        "export function main() {\n  let s = 0;\n  for (let i = 0; i < 10; i++) { s += i; }\n  return s;\n}\n";
    const FRACTIONAL_TS: &str = "export function main(n) { return n / 4; }\n";
    const RECURSIVE_TS: &str =
        "export function main(n) { if (n < 2) return n; return main(n - 1) + main(n - 2); }\n";

    fn cc_available() -> bool {
        Command::new("cc")
            .arg("--version")
            .output()
            .map(|out| out.status.success())
            .unwrap_or(false)
    }

    fn compile_and_run(c_source: &str, arg: Option<&str>) -> (Option<String>, Option<i32>) {
        let dir = tempfile::tempdir().expect("tempdir should be created");
        let c_path = dir.path().join("t.c");
        let bin_path = dir.path().join("t.bin");
        fs::write(&c_path, c_source).unwrap();
        let compile = Command::new("cc")
            .args(["-O2"])
            .arg(&c_path)
            .args(["-lm", "-o"])
            .arg(&bin_path)
            .output()
            .expect("cc invocation");
        assert!(
            compile.status.success(),
            "cc failed:\n{}",
            String::from_utf8_lossy(&compile.stderr)
        );
        let mut cmd = Command::new(&bin_path);
        if let Some(arg) = arg {
            cmd.arg(arg);
        }
        let output = cmd.output().expect("run compiled binary");
        let stdout = if output.status.success() {
            Some(
                String::from_utf8_lossy(&output.stdout)
                    .trim_end()
                    .to_string(),
            )
        } else {
            None
        };
        (stdout, output.status.code())
    }

    /// Lean oracle mirror #1/#2: sumBelow 900 = 404550, and the
    /// 2,000,000-iteration case the walker's hop cap can never reach —
    /// sumBelow 2000000 = 1999999000000 (Lean:
    /// aot_parity_oracle_sum_two_million via the closed form).
    #[test]
    fn numeric_loop_parity_sum_loop() {
        let c = numeric_loop_c(SUM_LOOP_TS, "main").expect("sum loop is in the class");
        if !cc_available() {
            return;
        }
        assert_eq!(
            compile_and_run(&c, Some("900")).0.as_deref(),
            Some("404550")
        );
        assert_eq!(
            compile_and_run(&c, Some("2000000")).0.as_deref(),
            Some("1999999000000")
        );
    }

    /// Lean oracle mirror #3: four sequential loops at n=5 give 50 —
    /// the same program the FOIL estimator certifies at degree 1.
    #[test]
    fn numeric_loop_parity_sequential_loops() {
        let c = numeric_loop_c(SEQ_LOOPS_TS, "main").expect("seq loops are in the class");
        if !cc_available() {
            return;
        }
        assert_eq!(compile_and_run(&c, Some("5")).0.as_deref(), Some("50"));
    }

    /// Lean oracle mirror #4: the literal-trip loop gives 45 with no
    /// input at all (zero-parameter protocol).
    #[test]
    fn numeric_loop_parity_bounded_loop() {
        let c = numeric_loop_c(BOUNDED_TS, "main").expect("bounded loop is in the class");
        if !cc_available() {
            return;
        }
        assert_eq!(compile_and_run(&c, None).0.as_deref(), Some("45"));
        // Zero-param programs ignore argv entirely.
        assert_eq!(compile_and_run(&c, Some("null")).0.as_deref(), Some("45"));
    }

    /// Divergence-risk cases DECLINE (exit 3) rather than answer: a
    /// non-integral result and an unparseable input both hand the run
    /// back to the walker, so the AOT lane can never disagree with it.
    #[test]
    fn numeric_loop_declines_divergence_risk() {
        let c = numeric_loop_c(FRACTIONAL_TS, "main").expect("compiles fine");
        if !cc_available() {
            return;
        }
        let (out, code) = compile_and_run(&c, Some("2"));
        assert_eq!(out, None, "0.5 must not be printed by the AOT lane");
        assert_eq!(code, Some(3), "non-integral result declines");
        let (out, code) = compile_and_run(&c, Some("null"));
        assert_eq!(out, None);
        assert_eq!(code, Some(3), "unparseable input declines");
        let (out, code) = compile_and_run(&c, Some("8"));
        assert_eq!(out.as_deref(), Some("2"), "integral results answer");
        assert_eq!(code, Some(0));
    }

    /// Lean oracle mirror #6: local helper composition —
    /// `add(s, double_it(i))` over ten iterations gives 90
    /// (2 * sumBelow 10). Helpers compile to static C functions; the
    /// call graph must be acyclic.
    #[test]
    fn numeric_loop_parity_helper_functions() {
        let src = "function double_it(x) { return x * 2; }\n\
                   function add(a, b) { return a + b; }\n\
                   export function main(n) {\n  let s = 0;\n  for (let i = 0; i < n; i++) { s = add(s, double_it(i)); }\n  return s;\n}\n";
        let c = numeric_loop_c(src, "main").expect("helper composition is in the class");
        if !cc_available() {
            return;
        }
        assert_eq!(compile_and_run(&c, Some("10")).0.as_deref(), Some("90"));
    }

    /// Lean oracle mirror #7: the exactly-representable Math.*
    /// intrinsics — floor(9/2) + max(1,2,3) + abs(0-4) + min(9,5) = 16.
    #[test]
