        let src = "export function main(n) {\n  return Math.floor(n / 2) + Math.max(1, 2, 3) + Math.abs(0 - 4) + Math.min(9, 5);\n}\n";
        let c = numeric_loop_c(src, "main").expect("Math intrinsics are in the class");
